import type { ListTransactionsResult } from "@nomicfoundation/ignition-core";

import { HardhatError } from "@nomicfoundation/hardhat-errors";
import json5 from "json5";

export async function calculateListTransactionsDisplay(
  deploymentId: string,
  listTransactionsResult: ListTransactionsResult,
  configUrl?: string,
): Promise<string> {
  let text = `Logging transactions for deployment ${deploymentId}\n\n`;

  for (const [index, transaction] of listTransactionsResult.entries()) {
    const txLink = getTransactionLink(
      transaction.txHash,
      configUrl ?? transaction.browserUrl,
    );

    text += `Transaction ${index + 1}${txLink === undefined ? "" : txLink}:\n`;
    text += `  - Type: ${transactionTypeToDisplayType(transaction.type)}\n`;
    text += `  - Status: ${transaction.status}\n`;
    text += `  - TxHash: ${transaction.txHash}\n`;
    text += `  - From: ${transaction.from}\n`;

    if (transaction.to !== undefined) {
      text += `  - To: ${transaction.to}\n`;
    }

    if (transaction.name !== undefined) {
      text += `  - Name: ${transaction.name}\n`;
    }

    if (transaction.address !== undefined) {
      text += `  - Address: ${transaction.address}\n`;
    }

    if (transaction.params !== undefined) {
      text += `  - Params: ${json5.stringify(
        transaction.params,
        transactionDisplaySerializeReplacer,
      )}\n`;
    }

    if (transaction.value !== undefined) {
      text += `  - Value: '${transaction.value}n'\n`;
    }

    text += "\n";
  }

  return text;
}

function transactionTypeToDisplayType(type: string): string {
  switch (type) {
    case "DEPLOYMENT_EXECUTION_STATE":
      return "Contract Deployment";
    case "CALL_EXECUTION_STATE":
      return "Function Call";
    case "SEND_DATA_EXECUTION_STATE":
      return "Generic Transaction";
    default:
      throw new HardhatError(
        HardhatError.ERRORS.IGNITION.INTERNAL.UNKNOWN_TRANSACTION_TYPE,
        { type },
      );
  }
}

export function transactionDisplaySerializeReplacer(
  _key: string,
  value: unknown,
): unknown {
  if (typeof value === "bigint") {
    return `${value}n`;
  }

  return value;
}

function getTransactionLink(
  txHash: string,
  browserURL?: string,
): string | undefined {
  if (browserURL === undefined) {
    return undefined;
  }

  return `\x1b]8;;${browserURL}/tx/${txHash}\x1b\\ (🔗 view on block explorer)\x1b]8;;\x1b\\`;
}

import { execFileSync, execSync, type StdioOptions } from "node:child_process";
import { existsSync, readFileSync } from "node:fs";
import { resolve } from "node:path";

export const ROOT_DIR = resolve(import.meta.dirname, "../../..");
export const VERDACCIO_DIR = resolve(ROOT_DIR, ".verdaccio");
export const VERDACCIO_CONFIG = resolve(VERDACCIO_DIR, "config.yaml");
export const VERDACCIO_STORAGE = resolve(VERDACCIO_DIR, "storage");
export const VERDACCIO_HTPASSWD = resolve(VERDACCIO_DIR, "htpasswd");
export const VERDACCIO_LOG = resolve(VERDACCIO_DIR, "server.log");
export const VERDACCIO_PID_FILE = resolve(VERDACCIO_DIR, "verdaccio.pid");
export const VERDACCIO_NPMRC = resolve(VERDACCIO_DIR, ".npmrc");
export const VERDACCIO_SERVER = resolve(import.meta.dirname, "../server.ts");
export const VERDACCIO_HOST = "127.0.0.1";
export const VERDACCIO_PORT = 4873;
export const VERDACCIO_URL = `http://${VERDACCIO_HOST}:${VERDACCIO_PORT}`;

export function isVerdaccioRunning(): boolean {
  if (!existsSync(VERDACCIO_PID_FILE)) {
    return false;
  }

  const pid = parseInt(readFileSync(VERDACCIO_PID_FILE, "utf-8").trim(), 10);

  try {
    process.kill(pid, 0);
    return true;
  } catch {
    return false;
  }
}

let gitPath: string | undefined;

let npmPath: string | undefined;

let pnpmPath: string | undefined;

function which(command: string): string {
  return execSync(`which ${command}`, { encoding: "utf-8" }).trim();
}

export function git(args: string[]): string {
  if (gitPath === undefined) {
    gitPath = which("git");
  }

  return execFileSync(gitPath, args, {
    encoding: "utf-8",
    cwd: ROOT_DIR,
  }).trim();
}

export function npm(
  args: string[],
  stdio?: StdioOptions,
  env?: NodeJS.ProcessEnv,
): string {
  if (npmPath === undefined) {
    npmPath = which("npm");
  }

  const result = execFileSync(npmPath, args, {
    encoding: "utf-8",
    cwd: ROOT_DIR,
    stdio,
    env,
  });

  return (result ?? "").trim();
}

export function pnpm(
  args: string[],
  stdio?: StdioOptions,
  env?: NodeJS.ProcessEnv,
): string {
  if (pnpmPath === undefined) {
    pnpmPath = which("pnpm");
  }

  // When stdio is "inherit", execFileSync returns null (stdout is not captured)
  const result = execFileSync(pnpmPath, args, {
    encoding: "utf-8",
    cwd: ROOT_DIR,
    stdio,
    env,
  });

  return (result ?? "").trim();
}
